getDocuments.script:
(() => {
  const text = document.body?.innerText || ''

  if (text.includes('Only') && text.includes('workspace owners can view this page')) {
    throw new Error('Slack billing history is only available to workspace owners. Please sign in with a Slack workspace owner account.')
  }

  if (!window.boot_data?.api_token) {
    throw new Error('Slack billing API token not found. Make sure you are signed in and can access billing history.')
  }

  return true
})()

(async () => {
  const apiToken = window.boot_data?.api_token
  if (!apiToken) {
    throw new Error('Slack billing API token not found. Make sure you are signed in and can access billing history.')
  }

  const formData = new FormData()
  formData.append('token', apiToken)
  formData.append('limit', 50) // 50 items is an API limit

  const response = await fetch(
    'https://{{config.workspace-id}}.slack.com/api/payments.billing.history.list',
    { method: 'POST', body: formData },
  )

  if (!response.ok) {
    throw new Error(`Slack billing history request failed: HTTP ${response.status}`)
  }

  const data = await response.json()

  if (data.ok === false) {
    const reason = data.error ? ` (${data.error})` : ''
    throw new Error(`Slack billing history API rejected the request${reason}. Please sign in with a Slack workspace owner account.`)
  }

  if (!Array.isArray(data.billing_items)) {
    throw new Error('Slack billing history API response did not include billing_items. Please sign in with a Slack workspace owner account that can access billing history.')
  }

  return data.billing_items
    .filter((item) => item.invoice && item.invoice.hosted_url)
    .map((item) => item.invoice.hosted_url)
})()
